@page "/notepad"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IJSRuntime JS

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<div class="mb-3">
    <textarea class="form-control" rows="12" @bind="content" @bind:event="oninput"
              placeholder="Type your notes here..."></textarea>
</div>

<div class="d-flex align-items-center gap-3 mb-3">
    <button class="btn btn-primary" @onclick="SaveNowAsync">Save now</button>
    <button class="btn btn-outline-danger" @onclick="ClearAsync">Clear</button>
    @if (lastSavedTime is not null)
    {
        <span class="text-muted">Last saved at @lastSavedTime</span>
    }
</div>

@code {
    private string content = string.Empty;
    private string savedContent = string.Empty;
    private string? lastSavedTime;
    private IJSObjectReference? module;
    private Timer? autoSaveTimer;

    private const string StorageKey = "notepad-content";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", Assets["Components/Pages/Notepad.razor.js"]);

            var stored = await module.InvokeAsync<string?>("load", StorageKey);
            if (!string.IsNullOrEmpty(stored))
            {
                content = stored;
                savedContent = stored;
                StateHasChanged();
            }

            autoSaveTimer = new Timer(async _ =>
            {
                if (content != savedContent)
                {
                    await InvokeAsync(async () =>
                    {
                        await SaveAsync();
                        StateHasChanged();
                    });
                }
            }, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
        }

        if (module is not null)
        {
            var hasUnsaved = content != savedContent;
            await module.InvokeVoidAsync("setBeforeUnload", hasUnsaved);
        }
    }

    private async Task SaveAsync()
    {
        if (module is null) return;
        await module.InvokeVoidAsync("save", StorageKey, content);
        savedContent = content;
        lastSavedTime = DateTime.Now.ToString("HH:mm:ss");
    }

    private async Task SaveNowAsync()
    {
        await SaveAsync();
    }

    private async Task ClearAsync()
    {
        content = string.Empty;
        savedContent = string.Empty;
        lastSavedTime = null;
        if (module is not null)
        {
            await module.InvokeVoidAsync("save", StorageKey, string.Empty);
            await module.InvokeVoidAsync("setBeforeUnload", false);
        }
    }

    public async ValueTask DisposeAsync()
    {
        autoSaveTimer?.Dispose();
        if (module is not null)
        {
            await module.InvokeVoidAsync("setBeforeUnload", false);
            await module.DisposeAsync();
        }
    }
}

let beforeUnloadHandler = null;

export function save(key, value) {
    localStorage.setItem(key, value);
}

export function load(key) {
    return localStorage.getItem(key);
}

export function setBeforeUnload(enable) {
    if (enable && !beforeUnloadHandler) {
        beforeUnloadHandler = (e) => {
            e.preventDefault();
        };
        window.addEventListener("beforeunload", beforeUnloadHandler);
    } else if (!enable && beforeUnloadHandler) {
        window.removeEventListener("beforeunload", beforeUnloadHandler);
        beforeUnloadHandler = null;
    }
}

